css_snippet:
body {
    font-family: 'Inter', sans-serif; /* Or any font with optical sizing support */
    font-optical-sizing: auto;
}

h1 {
    font-size: 3.5rem;
    font-weight: 700;
    font-optical-sizing: auto; /* Explicitly ensure for larger sizes */
}

p {
    font-size: 1.125rem;
    font-optical-sizing: auto;
}

/* For specific UI components where manual control is preferred: */
.caption-text {
    font-size: 0.875rem;
    font-optical-sizing: none; /* Disable automatic adjustment if needed */
}
